 1	import React, { Dispatch, FC, SetStateAction } from 'react';
 2	
 3	import { IoK8sApiCoreV1PersistentVolumeClaim } from '@kubevirt-ui/kubevirt-api/kubernetes';
 4	import { V1VirtualMachine } from '@kubevirt-ui/kubevirt-api/kubevirt';
 5	import { getName } from '@kubevirt-utils/resources/shared';
 6	import { getVolumes } from '@kubevirt-utils/resources/vm';
 7	import { readableSizeUnit } from '@kubevirt-utils/utils/units';
 8	import { Table, Tbody, Td, Th, Thead, Tr } from '@patternfly/react-table';
 9	
10	import { columnNames } from './constants';
11	import { getTableDiskData } from './utils';
12	
13	type SelectMigrationDisksTableProps = {
14	  pvcs: IoK8sApiCoreV1PersistentVolumeClaim[];
15	  selectedPVCs: IoK8sApiCoreV1PersistentVolumeClaim[];
16	  setSelectedPVCs: Dispatch<SetStateAction<IoK8sApiCoreV1PersistentVolumeClaim[]>>;
17	  vm: V1VirtualMachine;
18	};
19	
20	const SelectMigrationDisksTable: FC<SelectMigrationDisksTableProps> = ({
21	  pvcs,
22	  selectedPVCs,
23	  setSelectedPVCs,
24	  vm,
25	}) => {
26	  const tableData = getVolumes(vm)?.map((volume) => getTableDiskData(vm, volume, pvcs));
27	
28	  const selectableData = tableData.filter((data) => data.isSelectable);
29	
30	  return (
31	    <Table aria-label="Selectable table">
32	      <Thead>
33	        <Tr>
34	          <Th
35	            select={{
36	              isSelected: selectedPVCs?.length === selectableData.length,
37	              onSelect: (_event, isSelecting) =>
38	                setSelectedPVCs(isSelecting ? selectableData.map((data) => data.pvc) : []),
39	            }}
40	            aria-label="Row select"
41	          />
42	          <Th>{columnNames.name}</Th>
43	          <Th>{columnNames.drive}</Th>
44	          <Th>{columnNames.storageClass}</Th>
45	          <Th>{columnNames.size}</Th>
46	        </Tr>
47	      </Thead>
48	      <Tbody>
49	        {tableData.map((diskData, rowIndex) => (
50	          <Tr key={diskData.name}>
51	            <Td
52	              select={{
53	                isDisabled: !diskData.isSelectable,
54	                isSelected: Boolean(
55	                  selectedPVCs.find((pvc) => getName(pvc) === getName(diskData.pvc)),
56	                ),
57	                onSelect: (_event, isSelecting) =>
58	                  setSelectedPVCs((selection) =>
59	                    isSelecting
60	                      ? [...selection, diskData.pvc]
61	                      : selection.filter((pvc) => getName(pvc) !== getName(diskData.pvc)),
62	                  ),
63	                rowIndex,
64	              }}
65	            />
66	            <Td dataLabel={columnNames.name}>{diskData.name}</Td>
67	            <Td dataLabel={columnNames.drive}>{diskData.drive}</Td>
68	            <Td dataLabel={columnNames.storageClass}>{diskData.storageClass}</Td>
69	            <Td dataLabel={columnNames.size}>{readableSizeUnit(diskData?.size)}</Td>
70	          </Tr>
71	        ))}
72	      </Tbody>
73	    </Table>
74	  );
75	};
76	
77	export default SelectMigrationDisksTable;

